#!/usr/bin/env node
// time-and-date MCP stub. Methods:
//   now({tz}) → ISO + tz-shifted human string
//   addDays({iso, days}) → ISO
//   diff({a, b, unit}) → number
process.stdin.setEncoding('utf8');
let buf = '';
process.stdin.on('data', (chunk) => {
  buf += chunk;
  let idx;
  while ((idx = buf.indexOf('\n')) >= 0) {
    const line = buf.slice(0, idx);
    buf = buf.slice(idx + 1);
    if (!line.trim()) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { continue; }
    const id = msg.id;
    const method = msg.method;
    const params = msg.params || {};
    if (method === 'initialize') {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, result: { protocolVersion: '0.1.0', capabilities: {}, serverInfo: { name: 'time-and-date', version: '0.1.0' } } }) + '\n');
      continue;
    }
    if (method === 'now') {
      const tz = params.tz || 'UTC';
      const d = new Date();
      let human;
      try { human = d.toLocaleString('en-US', { timeZone: tz }); }
      catch { human = d.toISOString(); }
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, result: { iso: d.toISOString(), tz, human } }) + '\n');
      continue;
    }
    if (method === 'addDays') {
      const d = new Date(params.iso || Date.now());
      d.setDate(d.getDate() + Number(params.days || 0));
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, result: { iso: d.toISOString() } }) + '\n');
      continue;
    }
    if (method === 'diff') {
      const a = new Date(params.a).getTime();
      const b = new Date(params.b).getTime();
      const ms = b - a;
      const unit = params.unit || 'ms';
      const factors = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
      const factor = factors[unit] || 1;
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, result: { value: ms / factor, unit } }) + '\n');
      continue;
    }
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, error: { code: -32601, message: 'unknown method' } }) + '\n');
  }
});
